"use strict";const e=require("../request.js");exports.getGlobalNews=function(t=!1,n=!1,o=60){const r=`mode=global&important=${n}&limit=${o}${t?"&force=true":""}`;return e.get(`/api/fund/news?${r}`,{loadingText:"读取资讯"})},exports.getHoldingNews=function(t,n=!1,o=!1,r=40){const i=`username=${encodeURIComponent(t)}&important=${o}&limit=${r}${n?"&force=true":""}`;return e.get(`/api/fund/holding-news?${i}`,{loadingText:"读取持仓资讯"})};
